def promedio_frecuencia(mediciones: list[float]) -> float:
    if len(mediciones) != 3:
        raise ValueError('Se requieren exactamente tres mediciones')
    if any(valor <= 0 for valor in mediciones):
        raise ValueError('Las mediciones deben ser positivas')
    return sum(mediciones) / len(mediciones)

resultado = promedio_frecuencia([72.0, 75.0, 78.0])
print(f'{resultado:.1f} lpm')

def concentracion_mg_ml(masa_mg: float, volumen_ml: float) -> float:
    if not isinstance(masa_mg, (int, float)) or not isinstance(volumen_ml, (int, float)):
        raise TypeError('masa y volumen deben ser numéricos')
    if masa_mg < 0:
        raise ValueError('masa_mg no puede ser negativa')
    if volumen_ml <= 0:
        raise ValueError('volumen_ml debe ser positivo')
    return float(masa_mg) / float(volumen_ml)

assert abs(concentracion_mg_ml(25, 10) - 2.5) < 1e-12
